mapper.select:
SELECT NVL(COUNT(*), 0) FROM campingCar c
AND carShow = #{carShow}
AND

SELECT c.carNum, thumbnail, carName, d.weekCost, d.wkndCost, discountRate, TO_CHAR(reg_date, 'YYYY-MM-DD') reg_date FROM campingCar c JOIN carDetail d ON c.carNum = d.carNum
AND carShow = #{carShow}
ORDER BY c.carNum DESC OFFSET #{offset} ROWS FETCH FIRST #{size} ROWS ONLY
